SELECT COALESCE(SUM(amount), 0) AS "total"
FROM szzw.t_yqyc_biz_bu_performance
WHERE stat_month = #{month} and service_id = #{serviceId}

SELECT COALESCE(SUM(amount), 0) AS "total"
FROM szzw.t_yqyc_biz_bu_performance
WHERE stat_month LIKE #{year} || '%' and service_id = #{serviceId}

SELECT p.bu_org_id AS "buOrgId", o.org_name AS "buName", p.service_id AS "serviceId", COALESCE(SUM(p.amount), 0) AS "amount" FROM szzw.t_yqyc_biz_bu_performance p JOIN szzw.t_yqyc_sys_org o ON p.bu_org_id = o.id WHERE p.stat_month = #{month}
AND p.service_id IN
#{code}
GROUP BY p.bu_org_id, o.org_name, p.service_id

SELECT p.bu_org_id AS "buOrgId", o.org_name AS "buName", COALESCE(SUM(p.amount), 0) AS "amount" FROM szzw.t_yqyc_biz_bu_performance p JOIN szzw.t_yqyc_sys_org o ON p.bu_org_id = o.id WHERE p.stat_month = #{month}
AND p.service_id IN
#{code}
GROUP BY p.bu_org_id, o.org_name ORDER BY SUM(p.amount) DESC

